Hrvatska se s 38,6 % BDP-a smješta u gornju polovicu raspona, iznad Njemačke i osjetno iznad prosjeka OECD-a, ali ispod nordijskih i većine kontinentalnih sustava. Po ukupnoj visini tereta time nije iznimka, no prava se posebnost vidi tek u strukturi prihoda.

Struktura prihoda razdvaja modele jasnije od same visine poreza, jer zemlje sličnog ukupnog tereta mogu počivati na posve različitim osnovicama. Kružne slike (pite) prikazuju taj fiskalni otisak za nekoliko karakterističnih sustava, svaki sveden na tri glavne skupine poreza, pri čemu je zlatnim obrubom istaknuta Hrvatska.

::: {.content-visible when-format="html"}
```{ojs}
//| echo: false
//| label: fig-struktura-pita
//| fig-cap: "Struktura poreznih prihoda po glavnim skupinama poreza (udio u ukupnim prihodima). Hrvatska se, kao i Čile, oslanja na potrošnju, Danska na dohodak, a Njemačka na doprinose. Izvor: OECD, Revenue Statistics 2025; Hrvatska prema Eurostatu (2024.)."
//| fig-alt: "Šest kružnih dijagrama (pita), po jedan za OECD prosjek, Dansku, Njemačku, SAD, Čile i Hrvatsku. Svaka pita dijeli prihode na potrošnju, dohodak i dobit te doprinose. Hrvatska, istaknuta zlatnim obrubom, ima oko polovicu prihoda iz potrošnje."
{
  const cats = ["Potrošnja", "Dohodak i dobit", "Doprinosi"];
  const colors = {"Potrošnja": "#C8942D", "Dohodak i dobit": "#4A6B5C", "Doprinosi": "#6B1F26"};
  const zemlje = [
    {z: "OECD prosjek", v: [34, 38, 28], hl: false},
    {z: "Danska",       v: [30, 70, 0],  hl: false},
    {z: "Njemačka",     v: [28, 33, 39], hl: false},
    {z: "SAD",          v: [19, 55, 26], hl: false},
    {z: "Čile",         v: [57, 37, 6],  hl: false},
    {z: "Hrvatska",     v: [50, 20, 30], hl: true}
  ];
  const cols = 3, R = 64, padX = 30, padY = 16, titleH = 24, legendH = 36;
  const cellW = R * 2 + padX, cellH = R * 2 + titleH + padY;
  const rows = Math.ceil(zemlje.length / cols);
  const W = cols * cellW + padX, H = rows * cellH + legendH + padY;

  const pie = d3.pie().sort(null).value(d => d.val);
  const arc = d3.arc().innerRadius(0).outerRadius(R);
  const labelArc = d3.arc().innerRadius(R * 0.58).outerRadius(R * 0.58);

  const svg = d3.create("svg")
    .attr("viewBox", [0, 0, W, H])
    .attr("width", W)
    .attr("style", "max-width: 100%; height: auto; font-family: Public Sans, system-ui, sans-serif; background: #F2EDE3;");

  zemlje.forEach((d, i) => {
    const cx = padX + (i % cols) * cellW + R;
    const cy = padY + titleH + Math.floor(i / cols) * cellH + R;
    const g = svg.append("g").attr("transform", `translate(${cx},${cy})`);
    const slices = pie(cats.map((c, j) => ({cat: c, val: d.v[j]})));
    g.selectAll("path").data(slices).join("path")
      .attr("d", arc)
      .attr("fill", a => colors[a.data.cat])
      .attr("stroke", "#F2EDE3")
      .attr("stroke-width", 1.5)
      .append("title").text(a => a.data.cat + ": " + a.data.val + " %");
    g.selectAll("text").data(slices.filter(a => a.data.val >= 8)).join("text")
      .attr("transform", a => `translate(${labelArc.centroid(a)})`)
      .attr("text-anchor", "middle")
      .attr("dy", "0.35em")
      .attr("font-size", 12)
      .attr("font-weight", 600)
      .attr("fill", "white")
      .text(a => a.data.val + " %");
    if (d.hl) {
      svg.append("circle").attr("cx", cx).attr("cy", cy).attr("r", R + 5)
        .attr("fill", "none").attr("stroke", "#C8942D").attr("stroke-width", 2.5);
    }
    svg.append("text")
      .attr("x", cx).attr("y", cy - R - 9)
      .attr("text-anchor", "middle")
      .attr("font-size", 13.5)
      .attr("font-weight", d.hl ? 700 : 600)
      .attr("fill", d.hl ? "#9A6F38" : "#1C1916")
      .text(d.z);
  });

  const ly = H - legendH + 10;
  let lx = padX;
  cats.forEach(c => {
    svg.append("rect").attr("x", lx).attr("y", ly).attr("width", 14).attr("height", 14)
      .attr("rx", 2).attr("fill", colors[c]);
    svg.append("text").attr("x", lx + 19).attr("y", ly + 11.5)
      .attr("font-size", 12.5).attr("fill", "#3A332D").text(c);
    lx += 19 + c.length * 7.6 + 24;
  });

  return svg.node();
}
